  ('aboriginal-d0d1b9a2-moex-00080', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依中央總會計制度規定，公務機關會計報告，係彙總各公務機關普通公務單位會計與特種公務會 計應彙入中央總會計之財務資訊，下列敘述何者正確？', '["國庫出納會計之國庫存款、應付保管款，直接彙入公務機關會計後，再彙入總會計", "國庫出納會計應與各機關之普通公務單位會計核對收入支出繳領各科目及金額", "徵課會計僅以每年產製收入支出表及平衡表等作為原始憑證，記入普通公務單位會計", "國有財產會計應與各機關之普通公務單位會計核對公用及非公用財產金額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00081', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依中央政府整體資產負債表編製注意事項規定，有關整體資產負債表之敘述，下列何者錯誤？', '["係彙總表達公務機關、特種基金整體資產、負債等狀況，但不含政府代管之信託基金", "採資產減負債等於淨資產方式作為報導格式", "採分欄方式分別列示公務機關、特種基金－營業部分與非營業部分、內部往來沖銷，以及沖銷 調整後之合計數", "負債按流動負債和非流動負債之類別表達"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00082', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，乙市政府X2年度總預算，稅課收入編列150億 元，罰鍰收入編列8億元，規費收入編列10億元，發行公債編列20億元，中央政府補助款35億 元，X1年歲出保留10億元，移用以前年度歲計賸餘編列5億元，乙市政府X2年度「歲入預算 數」為若干？', '["233億元", "228億元", "223億元", "203億元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00083', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依政府會計準則公報第7號及中央政府普通公務單位會計制度之一致規定，乙機關於X1年8月 1日與B廠商發生訴訟，乙機關向B廠商要求賠付200萬元，經乙機關於X1年12月31日評估 幾乎確定可以獲得勝訴，乙機關應如何處理？', '["不作分錄，亦無須揭露相關資訊", "不作分錄，但須於會計報告揭露必要資訊", "借：應收帳款，貸：罰款及賠償收入", "借：繳付公庫數，貸：罰款及賠償收入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
